"""
This module represents the checkers board.
"""

import numpy as np
from termcolor import colored

class Piece:
    def __init__(self, player, type='normal'):
        self.player = player
        self.type = type
        self.is_king = False

    def promote(self):
        self.is_king = True

    def __str__(self):
        if self.player == 'white':
            return colored('W' if not self.is_king else 'WK', color='red')
        else:
            return colored('B' if not self.is_king else 'BK', color='blue')

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=object)
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in (1, 3, 5, 7) if i % 2 == 0 else (0, 2, 4, 6):
                self.board[i, j] = Piece('black')
        for i in range(5, 8):
            for j in (0, 2, 4, 6) if i % 2 != 0 else (1, 3, 5, 7):
                self.board[i, j] = Piece('white')

    def print_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece is not None else ' ' for piece in row))

    def move_piece(self, start_pos, end_pos):
        i1, j1 = start_pos
        i2, j2 = end_pos
        piece = self.board[i1, j1]
        self.board[i1, j1] = None
        if abs(j2 - j1) == 2:
            # Remove the captured piece
            capture_row = (i1 + i2) // 2
            capture_col = (j1 + j2) // 2
            self.board[capture_row, capture_col] = None
        self.board[i2, j2] = piece
        if piece.type == 'normal' and (i2 == 0 or i2 == 7):
            piece.promote()
```

