# board.py

class Board:
    def __init__(self):
        self.board = None

    def initialize_board(self):
        # Initialize an 8x8 checkerboard with alternating dark and light squares
        self.board = [[None for _ in range(8)] for _ in range(8)]
        piece_types = ['B', 'W']
        for i in range(3):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = piece_types[0]
        for i in range(5, 8):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = piece_types[1]

    def draw_board(self):
        for row in self.board:
            print(" ".join(f"{cell:3}" if cell else "   " for cell in row))
            print("-" * 30)

    def move_piece(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        piece = self.board[x1][y1]
        if piece and (x2 - x1 == 1 or x2 - x1 == -1) and abs(y2 - y1) == 1:
            self.board[x1][y1] = None
            self.board[x2][y2] = piece

    def is_valid_move(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        piece = self.board[x1][y1]
        if piece and (x2 - x1 == 1 or x2 - x1 == -1) and abs(y2 - y1) == 1:
            return True
        return False

    def check_capture(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        if abs(x2 - x1) == 2 and abs(y2 - y1) == 2:
            capture_x = (x1 + x2) // 2
            capture_y = (y1 + y2) // 2
            piece = self.board[capture_x][capture_y]
            if piece and piece != self.board[x1][y1]:
                self.board[capture_x][capture_y] = None
                return True
        return False

    def king_piece(self, pos):
        x, y = pos
        if self.board[x][y] == 'B' and x == 0 or self.board[x][y] == 'W' and x == 7:
            self.board[x][y] += 'K'

    def get_all_pieces(self, color=None):
        pieces = []
        for i in range(8):
            for j in range(8):
                if self.board[i][j]:
                    if not color or (color == 'B' and self.board[i][j][0] == 'B') or (color == 'W' and self.board[i][j][0] == 'W'):
                        pieces.append((i, j))
        return pieces

    def is_game_over(self):
        black_pieces = len(self.get_all_pieces('B'))
        white_pieces = len(self.get_all_pieces('W'))
        return black_pieces == 0 or white_pieces == 0
