from player import Player
from board import Board

class Game:
    def __init__(self):
        self.board = Board()
        self.board.initialize_board()
        self.players = [Player("Player 1", 'B'), Player("Player 2", 'W')]
        self.current_player_index = 0

    def switch_turn(self):
        self.current_player_index = 1 - self.current_player_index

    def get_valid_moves(self, player_color):
        valid_moves = []
        for piece in self.board.get_all_pieces(player_color):
            moves = self.get_piece_moves(piece)
            if moves:
                valid_moves.extend(moves)
        return valid_moves

    def make_move(self, from_pos, to_pos):
        if self.board.is_valid_move(from_pos, to_pos):
            if self.board.check_capture(from_pos, to_pos):
                self.board.move_piece(from_pos, to_pos)
                self.switch_turn()
            else:
                self.board.move_piece(from_pos, to_pos)
                self.board.king_piece(to_pos)
                self.switch_turn()

    def check_win_condition(self):
        if self.board.is_game_over():
            return True
        return False

    def get_piece_moves(self, piece):
        x, y = piece
        moves = []
        directions = [(1, 1), (1, -1), (-1, 1), (-1, -1)]
        for dx, dy in directions:
            move_to = (x + dx, y + dy)
            jump_to = (x + 2 * dx, y + 2 * dy)
            if self.board.is_valid_move((x, y), move_to):
                moves.append(move_to)
            if self.board.check_capture((x, y), jump_to):
                moves.append(jump_to)
        return moves
